import{_ as s,c as a,e as p,o as e}from"./app-DITrC0xQ.js";const t={};function l(o,n){return e(),a("div",null,[...n[0]||(n[0]=[p(`<h1 id="gowind-admin-风行-—-开箱即用的企业级全栈中后台框架-influxdb集成指南" tabindex="-1"><a class="header-anchor" href="#gowind-admin-风行-—-开箱即用的企业级全栈中后台框架-influxdb集成指南"><span>GoWind Admin｜风行 — 开箱即用的企业级全栈中后台框架：InfluxDB集成指南</span></a></h1><p>InfluxDB 是一款采用 Go 语言开发的开源分布式时序数据库，专为时间序列数据的高效存储、查询与分析设计，由 InfluxData 公司主导开发。其核心优势在于高频写入性能、时序数据索引优化及原生聚合分析能力，广泛应用于 IoT 设备监控、系统性能指标采集、日志时序分析、金融行情跟踪等场景。在企业级中后台系统中，InfluxDB 可快速对接 GoWind Admin 框架，为实时监控面板、历史数据追溯、趋势预测分析等功能提供稳定的数据存储支撑。</p><h2 id="一、influxdb-核心概念深度解析" tabindex="-1"><a class="header-anchor" href="#一、influxdb-核心概念深度解析"><span>一、InfluxDB 核心概念深度解析</span></a></h2><p>InfluxDB 的数据模型与传统关系型数据库存在显著差异，理解以下核心概念是实现高效集成的基础。可通过与 MySQL 概念的类比快速建立认知：</p><table><thead><tr><th><strong>概InfluxDB 概念</strong></th><th><strong>MySQL 类比</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td><strong>时间戳（Timestamp）</strong></td><td>主键（Primary Key）</td><td>每条数据必须包含的核心字段，记录数据产生的精确时间（默认精确到纳秒），采用 UTC 时间格式存储，是时序数据的唯一标识。若写入数据时未指定，InfluxDB 会自动填充服务端当前时间。</td></tr><tr><td><strong>测量（Measurement）</strong></td><td>表（Table）</td><td>用于归类同一类时序数据的集合，例如 &quot;cpu_usage&quot;（CPU 使用率）、&quot;stock_candle&quot;（股票 K 线）。无需预先创建，写入第一条数据时自动生成。</td></tr><tr><td><strong>标签（Tag）</strong></td><td>带索引的列（Indexed Column）</td><td>用于标识数据的元信息，仅支持字符串类型，默认建立索引，适合用于数据过滤、分组查询。示例：设备 ID（sensor_id=&quot;s1001&quot;）、地域（region=&quot;east&quot;）、股票代码（symbol=&quot;600000&quot;）。</td></tr><tr><td><strong>字段（Field）</strong></td><td>无索引的列（Non-indexed Column）</td><td>存储具体的测量数值，支持浮点数、整数、布尔值等类型，默认不建索引（避免高频写入时索引开销过大）。示例：温度值（temp=25.5）、CPU 使用率（usage=78.2）、股票收盘价（close=34.56）。</td></tr><tr><td><strong>保留策略（Retention Policy, RP）</strong></td><td>数据生命周期策略</td><td>定义数据的保留时长（Duration）和集群副本数（Replication，单机版无效），InfluxDB 会自动清理过期数据。默认策略为 autogen（永久保留），可自定义策略，例如：CREATE RETENTION POLICY &quot;30d_data&quot; ON &quot;finance&quot; DURATION 30d REPLICATION 1 DEFAULT（保留 30 天数据并设为默认策略）。</td></tr><tr><td><strong>系列（Series）</strong></td><td>分区表（Partition）</td><td>由「Measurement + Tag 集合」唯一确定的数据集，相当于对数据的细粒度分区。示例：stock_candle,symbol=600000 代表上证 600000 股票的 K 线时序数据。</td></tr><tr><td><strong>数据点（Point）</strong></td><td>数据行（Row）</td><td>单条时序数据记录，由 Measurement、Tag Set、Field Set、Timestamp 四部分组成，是 InfluxDB 中数据存储的最小单元。</td></tr></tbody></table><blockquote><p><strong>注意</strong>：InfluxDB 为无模式设计，无需预先定义 Measurement 结构，但同一 Field 多次写入不同类型数据会报错（Tag 因默认字符串类型无此问题）。</p></blockquote><h2 id="二、influxdb-2-x-与-3-x-核心差异对比" tabindex="-1"><a class="header-anchor" href="#二、influxdb-2-x-与-3-x-核心差异对比"><span>二、InfluxDB 2.x 与 3.x 核心差异对比</span></a></h2><p>InfluxDB 3.x 是基于 IOx 引擎的重大重构版本，在架构设计、性能表现、生态兼容上全面超越 2.x 版本。GoWind Admin 框架为追求最优性能与扩展性，仅支持 3.x 版本集成。以下是关键差异的详细对比：</p><h3 id="_2-1-存储引擎-从-tsm-到-iox-的代际飞跃" tabindex="-1"><a class="header-anchor" href="#_2-1-存储引擎-从-tsm-到-iox-的代际飞跃"><span>2.1 存储引擎：从 TSM 到 IOx 的代际飞跃</span></a></h3><ul><li><strong>InfluxDB 2.x</strong>：采用 TSM（Time-Structured Merge Tree）引擎，基于 LSM-Tree 改进，适合高频写入和简单时间范围查询，但复杂聚合（如多维度 SUM/AVG）、JOIN 操作性能较差，存储容量受单节点限制。</li><li><strong>InfluxDB 3.x</strong>：采用全新 IOx（InfluxDB IOx）引擎，基于 Apache Arrow 内存格式和 Parquet 列存格式： 列式存储：大幅提升聚合查询效率，尤其适合多字段统计分析场景；</li><li><strong>向量化执行</strong>：并行处理数据块，减少 CPU 缓存失效与分支预测开销；</li><li><strong>存算分离</strong>：支持 S3 等对象存储作为后端，可横向扩展至 PB 级数据存储，适配云原生部署。</li></ul><h3 id="_2-2-查询语言-从-flux-回归标准-sql" tabindex="-1"><a class="header-anchor" href="#_2-2-查询语言-从-flux-回归标准-sql"><span>2.2 查询语言：从 Flux 回归标准 SQL</span></a></h3><h4 id="influxdb-2-x" tabindex="-1"><a class="header-anchor" href="#influxdb-2-x"><span>InfluxDB 2.x：</span></a></h4><p>主推 Flux 函数式查询语言，语法灵活但学习曲线陡峭，示例：</p><div class="language-flux line-numbers-mode" data-highlighter="prismjs" data-ext="flux"><pre><code><span class="line">from(bucket: &quot;finance&quot;)</span>
<span class="line">	|&gt; range(start: -1h)</span>
<span class="line">	|&gt; filter(fn: (r) =&gt; r._measurement == &quot;stock_candle&quot; and r.symbol == &quot;600000&quot;)</span>
<span class="line">	|&gt; aggregateWindow(every: 5m, fn: mean, columns: [&quot;close&quot;])</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="influxdb-3-x" tabindex="-1"><a class="header-anchor" href="#influxdb-3-x"><span>InfluxDB 3.x：</span></a></h4><p>回归标准 SQL 作为主力查询语言，降低 SQL 开发者学习成本，同时兼容 Flux 脚本，支持窗口函数、JOIN 等复杂操作：</p><div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">SELECT</span> symbol<span class="token punctuation">,</span> <span class="token function">AVG</span><span class="token punctuation">(</span><span class="token keyword">close</span><span class="token punctuation">)</span> <span class="token keyword">AS</span> avg_close </span>
<span class="line"><span class="token keyword">FROM</span> stock_candle </span>
<span class="line"><span class="token keyword">WHERE</span> <span class="token keyword">time</span> <span class="token operator">&gt;</span> <span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">-</span> <span class="token keyword">INTERVAL</span> <span class="token string">&#39;1 hour&#39;</span> </span>
<span class="line">	<span class="token operator">AND</span> symbol <span class="token operator">=</span> <span class="token string">&#39;600000&#39;</span></span>
<span class="line"><span class="token keyword">GROUP</span> <span class="token keyword">BY</span> <span class="token keyword">time</span><span class="token punctuation">(</span><span class="token number">5</span>m<span class="token punctuation">)</span><span class="token punctuation">,</span> symbol<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-架构与扩展性-从单体到分布式云原生" tabindex="-1"><a class="header-anchor" href="#_2-3-架构与扩展性-从单体到分布式云原生"><span>2.3 架构与扩展性：从单体到分布式云原生</span></a></h3><table><thead><tr><th>维度</th><th>InfluxDB 2.x</th><th>InfluxDB 3.x</th></tr></thead><tbody><tr><td>架构模式</td><td>单体架构，企业版支持集群但部署复杂</td><td>原生分布式，存算分离设计</td></tr><tr><td>扩展能力</td><td>单节点写入吞吐量 10-50 万点/秒，适合中小规模场景</td><td>集群模式写入吞吐量达百万点/秒，支持 PB 级数据</td></tr><tr><td>云服务适配</td><td>基础云部署支持，无 Serverless 模式</td><td>支持 AWS/Azure Serverless 模式，按需付费</td></tr><tr><td>生态集成</td><td>依赖 Telegraf 采集、Grafana 可视化</td><td>原生支持 Prometheus、OpenTelemetry 数据接入，内置 AI 异常检测</td></tr><tr><td>生态集成</td><td>开源版（AGPLv3）+ 企业版（商业许可），功能差异大</td><td>混合许可：核心功能（IOx 引擎、SQL 查询）Apache 2.0 开源，高级功能（云服务、AI 工具）商业收费</td></tr></tbody></table><h2 id="三、influxdb-3-x-docker-部署指南-推荐" tabindex="-1"><a class="header-anchor" href="#三、influxdb-3-x-docker-部署指南-推荐"><span>三、InfluxDB 3.x Docker 部署指南（推荐）</span></a></h2><p>采用 Docker 部署可快速搭建 InfluxDB 3.x 环境，无需关注系统依赖，适合开发测试与生产环境快速交付。以下是完整部署步骤，含服务验证与管理后台配置：</p><h3 id="_3-1-部署-influxdb-3-x-服务端" tabindex="-1"><a class="header-anchor" href="#_3-1-部署-influxdb-3-x-服务端"><span>3.1 部署 InfluxDB 3.x 服务端</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># 拉取并启动 InfluxDB 3.x 容器</span></span>
<span class="line"><span class="token function">docker</span> run <span class="token parameter variable">-itd</span> <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--name</span> influxdb3-server <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-p</span> <span class="token number">8181</span>:8181 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-v</span> /data/influxdb3/meta:/var/lib/influxdb/meta <span class="token punctuation">\\</span>  <span class="token comment"># 元数据持久化</span></span>
<span class="line">  <span class="token parameter variable">-v</span> /data/influxdb3/data:/var/lib/influxdb/data <span class="token punctuation">\\</span>  <span class="token comment"># 数据持久化</span></span>
<span class="line">  <span class="token parameter variable">-v</span> /data/influxdb3/config:/etc/influxdb <span class="token punctuation">\\</span>          <span class="token comment"># 配置文件挂载</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_NODE_ID</span><span class="token operator">=</span><span class="token number">0</span> <span class="token punctuation">\\</span>                           <span class="token comment"># 节点 ID（集群模式需唯一）</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_HTTP_PORT_NUMBER</span><span class="token operator">=</span><span class="token number">8181</span> <span class="token punctuation">\\</span>               <span class="token comment"># HTTP 服务端口</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_HTTP_AUTH_ENABLED</span><span class="token operator">=</span>true <span class="token punctuation">\\</span>              <span class="token comment"># 启用认证</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_CREATE_ADMIN_TOKEN</span><span class="token operator">=</span>yes <span class="token punctuation">\\</span>              <span class="token comment"># 自动生成 admin token</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_DB</span><span class="token operator">=</span>finance <span class="token punctuation">\\</span>                          <span class="token comment"># 初始化数据库（金融场景示例）</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_ORGANIZATION</span><span class="token operator">=</span>primary <span class="token punctuation">\\</span>                <span class="token comment"># 初始化组织</span></span>
<span class="line">  bitnami/influxdb:latest</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-部署-influxdb-explorer-管理后台" tabindex="-1"><a class="header-anchor" href="#_3-2-部署-influxdb-explorer-管理后台"><span>3.2 部署 InfluxDB Explorer 管理后台</span></a></h3><p>InfluxDB 3.x 分离了服务端与管理界面，需单独部署 Explorer 组件：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># 启动 Explorer 管理后台</span></span>
<span class="line"><span class="token function">docker</span> run <span class="token parameter variable">-itd</span> <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--name</span> influxdb3-explorer <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-p</span> <span class="token number">8888</span>:80 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--link</span> influxdb3-server:influxdb <span class="token punctuation">\\</span>  <span class="token comment"># 关联服务端容器</span></span>
<span class="line">  quay.io/influxdb/influxdb3-explorer:latest <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--mode</span><span class="token operator">=</span>admin</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-3-部署验证与初始化配置" tabindex="-1"><a class="header-anchor" href="#_3-3-部署验证与初始化配置"><span>3.3 部署验证与初始化配置</span></a></h3><ol><li><strong>服务可用性检查</strong>：执行 <code>docker logs influxdb3-server</code>，若输出 &quot;Started HTTP server on :8181&quot; 说明服务启动成功；</li><li><strong>获取 Admin Token</strong>：通过日志提取自动生成的 token： <code>docker logs influxdb3-server | grep &quot;Admin token&quot;</code></li><li><strong>连接管理后台</strong>：访问 <a href="http://localhost:8888" target="_blank" rel="noopener noreferrer">http://localhost:8888</a>，在连接配置页填写： Connection Name：自定义名称（如 &quot;GoWind-InfluxDB&quot;）</li><li>Host：<a href="http://influxdb3-server:8181" target="_blank" rel="noopener noreferrer">http://influxdb3-server:8181</a>（容器内关联地址）或 <a href="http://host.docker.internal:8181" target="_blank" rel="noopener noreferrer">http://host.docker.internal:8181</a>（Windows/macOS 本地）</li><li>Token：填写步骤 2 获取的 Admin Token</li><li>Organization：primary（与部署时环境变量一致）</li><li>Database：finance</li><li><strong>测试数据写入</strong>：在 Explorer 的 Query 页面执行 SQL，验证写入功能：<div class="language-sql line-numbers-mode" data-highlighter="prismjs" data-ext="sql"><pre><code><span class="line"><span class="token keyword">INSERT</span> <span class="token keyword">INTO</span> stock_candle <span class="token punctuation">(</span>symbol<span class="token punctuation">,</span> <span class="token keyword">open</span><span class="token punctuation">,</span> high<span class="token punctuation">,</span> low<span class="token punctuation">,</span> <span class="token keyword">close</span><span class="token punctuation">,</span> volume<span class="token punctuation">,</span> <span class="token keyword">time</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">VALUES</span> <span class="token punctuation">(</span><span class="token string">&#39;600000&#39;</span><span class="token punctuation">,</span> <span class="token number">34.2</span><span class="token punctuation">,</span> <span class="token number">34.8</span><span class="token punctuation">,</span> <span class="token number">34.0</span><span class="token punctuation">,</span> <span class="token number">34.5</span><span class="token punctuation">,</span> <span class="token number">1200000</span><span class="token punctuation">,</span> <span class="token function">NOW</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token comment">-- 验证查询</span></span>
<span class="line"><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> stock_candle <span class="token keyword">WHERE</span> symbol <span class="token operator">=</span> <span class="token string">&#39;600000&#39;</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><h3 id="_3-4-2-x-版本部署-兼容参考" tabindex="-1"><a class="header-anchor" href="#_3-4-2-x-版本部署-兼容参考"><span>3.4 2.x 版本部署（兼容参考）</span></a></h3><p>若需兼容旧系统，可参考以下 2.x 部署命令（GoWind Admin 不推荐）：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> run <span class="token parameter variable">-itd</span> <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">--name</span> influxdb2-server <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-p</span> <span class="token number">8086</span>:8086 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-v</span> /data/influxdb2:/var/lib/influxdb2 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_HTTP_AUTH_ENABLED</span><span class="token operator">=</span>true <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_ADMIN_USER</span><span class="token operator">=</span>admin <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_ADMIN_USER_PASSWORD</span><span class="token operator">=</span>GoWind@2024 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_ADMIN_USER_TOKEN</span><span class="token operator">=</span>gowind_admin_token_2024 <span class="token punctuation">\\</span></span>
<span class="line">  <span class="token parameter variable">-e</span> <span class="token assign-left variable">INFLUXDB_DB</span><span class="token operator">=</span>finance <span class="token punctuation">\\</span></span>
<span class="line">  bitnami/influxdb:2.7.11</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>管理后台访问 <a href="http://localhost:8086" target="_blank" rel="noopener noreferrer">http://localhost:8086</a>，使用上述账号密码登录即可。</p><h2 id="四、gowind-admin-集成-influxdb-3-x-完整步骤" tabindex="-1"><a class="header-anchor" href="#四、gowind-admin-集成-influxdb-3-x-完整步骤"><span>四、GoWind Admin 集成 InfluxDB 3.x 完整步骤</span></a></h2><p>GoWind Admin 已封装 InfluxDB 3.x SDK 核心能力，提供配置驱动的客户端初始化、数据模型映射、通用 CRUD 封装，集成过程简洁高效。以下以「股票 K 线数据存储」为例，完整演示集成流程：</p><h3 id="_4-1-安装依赖库" tabindex="-1"><a class="header-anchor" href="#_4-1-安装依赖库"><span>4.1 安装依赖库</span></a></h3><p>执行以下命令安装框架封装的 InfluxDB 客户端库：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">go get github.com/tx7do/kratos-bootstrap/database/influxdb</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_4-2-配置文件编写" tabindex="-1"><a class="header-anchor" href="#_4-2-配置文件编写"><span>4.2 配置文件编写</span></a></h3><p>在项目配置目录 <code>configs/data.yaml</code> 中添加 InfluxDB 配置节点，参数与部署时保持一致：</p><div class="language-yaml line-numbers-mode" data-highlighter="prismjs" data-ext="yml"><pre><code><span class="line"><span class="token key atrule">data</span><span class="token punctuation">:</span></span>
<span class="line">  <span class="token comment"># 其他数据库配置（MySQL、Redis 等）</span></span>
<span class="line">  <span class="token key atrule">influxdb</span><span class="token punctuation">:</span></span>
<span class="line">    <span class="token key atrule">host</span><span class="token punctuation">:</span> <span class="token string">&quot;http://localhost:8181&quot;</span>        <span class="token comment"># 服务端地址</span></span>
<span class="line">    <span class="token key atrule">token</span><span class="token punctuation">:</span> <span class="token string">&quot;apiv3_yYde4mJo0BYC7Ipi_00ZEex-A8if4swdqTBXiO-lCUDKhsIavHlRCQfo3p_DzI7S34ADHOC7Qxf600VVgW6LQQ&quot;</span>  <span class="token comment"># 管理员 Token</span></span>
<span class="line">    <span class="token key atrule">database</span><span class="token punctuation">:</span> <span class="token string">&quot;finance&quot;</span>                  <span class="token comment"># 目标数据库</span></span>
<span class="line">    <span class="token key atrule">organization</span><span class="token punctuation">:</span> <span class="token string">&quot;primary&quot;</span>              <span class="token comment"># 组织名称</span></span>
<span class="line">    <span class="token key atrule">timeout</span><span class="token punctuation">:</span> <span class="token number">5000</span>                        <span class="token comment"># 连接超时时间（毫秒）</span></span>
<span class="line">    <span class="token key atrule">retry</span><span class="token punctuation">:</span> <span class="token number">2</span>                             <span class="token comment"># 重试次数</span></span>
<span class="line">    <span class="token key atrule">retention_policy</span><span class="token punctuation">:</span> <span class="token string">&quot;30d_data&quot;</span>         <span class="token comment"># 数据保留策略（需提前创建）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-3-客户端初始化与依赖注入" tabindex="-1"><a class="header-anchor" href="#_4-3-客户端初始化与依赖注入"><span>4.3 客户端初始化与依赖注入</span></a></h3><p>在 <code>internal/data/influxdb_client.go</code> 中实现客户端初始化逻辑，并通过 Wire 完成依赖注入：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> data</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">  <span class="token string">&quot;github.com/go-kratos/kratos/v2/log&quot;</span></span>
<span class="line">  <span class="token string">&quot;github.com/tx7do/kratos-bootstrap/database/influxdb&quot;</span></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/conf&quot;</span>  <span class="token comment">// 替换为实际的配置包路径</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// NewInfluxdbClient 初始化 InfluxDB 客户端</span></span>
<span class="line"><span class="token comment">// 参数：logger 日志组件，cfg 全局配置</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewInfluxdbClient</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> cfg <span class="token operator">*</span>conf<span class="token punctuation">.</span>Bootstrap<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>influxdb<span class="token punctuation">.</span>Client<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// 从配置文件读取 InfluxDB 配置</span></span>
<span class="line">  influxCfg <span class="token operator">:=</span> cfg<span class="token punctuation">.</span>Data<span class="token punctuation">.</span>Influxdb</span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 框架封装的初始化方法，内置日志、超时、重试配置</span></span>
<span class="line">  cli<span class="token punctuation">,</span> err <span class="token operator">:=</span> influxdb<span class="token punctuation">.</span><span class="token function">NewClient</span><span class="token punctuation">(</span></span>
<span class="line">    logger<span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithHost</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Host<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithToken</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Token<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithDatabase</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Database<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithOrganization</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Organization<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithTimeout</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Timeout<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithRetryCount</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>Retry<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithRetentionPolicy</span><span class="token punctuation">(</span>influxCfg<span class="token punctuation">.</span>RetentionPolicy<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;初始化 InfluxDB 客户端失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;error&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> err</span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  log<span class="token punctuation">.</span><span class="token function">Infow</span><span class="token punctuation">(</span><span class="token string">&quot;InfluxDB 客户端初始化成功&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;host&quot;</span><span class="token punctuation">,</span> influxCfg<span class="token punctuation">.</span>Host<span class="token punctuation">,</span> <span class="token string">&quot;database&quot;</span><span class="token punctuation">,</span> influxCfg<span class="token punctuation">.</span>Database<span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">return</span> cli<span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在 <code>internal/data/init.go</code> 中注册依赖注入 <code>Provider</code>：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">//go:build wireinject</span></span>
<span class="line"><span class="token comment">// +build wireinject</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">package</span> data</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">  <span class="token string">&quot;github.com/google/wire&quot;</span></span>
<span class="line">  <span class="token string">&quot;github.com/go-kratos/kratos/v2/log&quot;</span></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/conf&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 依赖注入 Provider 集合，将 InfluxDB 客户端注入到业务层</span></span>
<span class="line"><span class="token keyword">var</span> ProviderSet <span class="token operator">=</span> wire<span class="token punctuation">.</span><span class="token function">NewSet</span><span class="token punctuation">(</span></span>
<span class="line">  NewInfluxdbClient<span class="token punctuation">,</span>       <span class="token comment">// InfluxDB 客户端</span></span>
<span class="line">  NewCandleRepo<span class="token punctuation">,</span>           <span class="token comment">// K 线数据仓库（后续实现）</span></span>
<span class="line">  <span class="token comment">// 其他数据层组件...</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// InitData 初始化数据层组件（Wire 自动生成代码）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">InitData</span><span class="token punctuation">(</span>cfg <span class="token operator">*</span>conf<span class="token punctuation">.</span>Bootstrap<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>Data<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token function">panic</span><span class="token punctuation">(</span>wire<span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span>NewData<span class="token punctuation">,</span> ProviderSet<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-4-业务模型定义" tabindex="-1"><a class="header-anchor" href="#_4-4-业务模型定义"><span>4.4 业务模型定义</span></a></h3><p>在 <code>internal/data/model/candle.go</code> 中定义股票 K 线模型，映射 InfluxDB 的 <code>Measurement</code> 结构：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> model</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">  <span class="token string">&quot;google.golang.org/protobuf/types/known/timestamppb&quot;</span></span>
<span class="line">  <span class="token string">&quot;time&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Candle 股票 K 线模型（对应 InfluxDB 的 stock_candle Measurement）</span></span>
<span class="line"><span class="token keyword">type</span> Candle <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">  Symbol    <span class="token operator">*</span><span class="token builtin">string</span>                <span class="token string">\`json:&quot;symbol&quot;\`</span>    <span class="token comment">// 股票代码（Tag）</span></span>
<span class="line">  Open      <span class="token operator">*</span><span class="token builtin">float64</span>               <span class="token string">\`json:&quot;open&quot;\`</span>      <span class="token comment">// 开盘价（Field）</span></span>
<span class="line">  High      <span class="token operator">*</span><span class="token builtin">float64</span>               <span class="token string">\`json:&quot;high&quot;\`</span>      <span class="token comment">// 最高价（Field）</span></span>
<span class="line">  Low       <span class="token operator">*</span><span class="token builtin">float64</span>               <span class="token string">\`json:&quot;low&quot;\`</span>       <span class="token comment">// 最低价（Field）</span></span>
<span class="line">  Close     <span class="token operator">*</span><span class="token builtin">float64</span>               <span class="token string">\`json:&quot;close&quot;\`</span>     <span class="token comment">// 收盘价（Field）</span></span>
<span class="line">  Volume    <span class="token operator">*</span><span class="token builtin">float64</span>               <span class="token string">\`json:&quot;volume&quot;\`</span>    <span class="token comment">// 成交量（Field）</span></span>
<span class="line">  Timestamp <span class="token operator">*</span>timestamppb<span class="token punctuation">.</span>Timestamp <span class="token string">\`json:&quot;timestamp&quot;\`</span> <span class="token comment">// 时间戳（精确到毫秒）</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// GetSymbol 获取股票代码（避免空指针）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Candle<span class="token punctuation">)</span> <span class="token function">GetSymbol</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> c<span class="token punctuation">.</span>Symbol <span class="token operator">==</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token string">&quot;&quot;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token operator">*</span>c<span class="token punctuation">.</span>Symbol</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 其他 Getter 方法（Open/High/Low/Close/Volume）类似，省略...</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// SetTimestamp 设置时间戳（兼容 time.Time 类型）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>c <span class="token operator">*</span>Candle<span class="token punctuation">)</span> <span class="token function">SetTimestamp</span><span class="token punctuation">(</span>t time<span class="token punctuation">.</span>Time<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  c<span class="token punctuation">.</span>Timestamp <span class="token operator">=</span> timestamppb<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>t<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-5-数据仓库实现-完整-crud" tabindex="-1"><a class="header-anchor" href="#_4-5-数据仓库实现-完整-crud"><span>4.5 数据仓库实现（完整 CRUD）</span></a></h3><p>在 <code>internal/data/repo/candle_repo.go</code> 中实现 K 线数据的 CRUD 操作，封装 InfluxDB 数据读写逻辑：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> repo</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">  <span class="token string">&quot;context&quot;</span></span>
<span class="line">  <span class="token string">&quot;errors&quot;</span></span>
<span class="line"></span>
<span class="line">  <span class="token string">&quot;github.com/InfluxCommunity/influxdb3-go/v2/influxdb3&quot;</span></span>
<span class="line">  <span class="token string">&quot;github.com/go-kratos/kratos/v2/log&quot;</span></span>
<span class="line">  <span class="token string">&quot;github.com/tx7do/kratos-bootstrap/database/influxdb&quot;</span></span>
<span class="line">  <span class="token string">&quot;google.golang.org/protobuf/types/known/timestamppb&quot;</span></span>
<span class="line"></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/data/model&quot;</span></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/errorx&quot;</span>  <span class="token comment">// 自定义错误包</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 常量定义：映射 InfluxDB 结构（避免硬编码）</span></span>
<span class="line"><span class="token keyword">const</span> <span class="token punctuation">(</span></span>
<span class="line">  MeasurementCandle <span class="token operator">=</span> <span class="token string">&quot;stock_candle&quot;</span> <span class="token comment">// 对应 InfluxDB 的 Measurement</span></span>
<span class="line">  </span>
<span class="line">  TagSymbol <span class="token operator">=</span> <span class="token string">&quot;symbol&quot;</span>               <span class="token comment">// Tag：股票代码</span></span>
<span class="line">  </span>
<span class="line">  FieldOpen   <span class="token operator">=</span> <span class="token string">&quot;open&quot;</span>               <span class="token comment">// Field：开盘价</span></span>
<span class="line">  FieldHigh   <span class="token operator">=</span> <span class="token string">&quot;high&quot;</span>               <span class="token comment">// Field：最高价</span></span>
<span class="line">  FieldLow    <span class="token operator">=</span> <span class="token string">&quot;low&quot;</span>                <span class="token comment">// Field：最低价</span></span>
<span class="line">  FieldClose  <span class="token operator">=</span> <span class="token string">&quot;close&quot;</span>              <span class="token comment">// Field：收盘价</span></span>
<span class="line">  FieldVolume <span class="token operator">=</span> <span class="token string">&quot;volume&quot;</span>             <span class="token comment">// Field：成交量</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CandleRepo 股票 K 线数据仓库接口</span></span>
<span class="line"><span class="token keyword">type</span> CandleRepo <span class="token keyword">interface</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token function">Create</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> candle <span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">)</span> <span class="token builtin">error</span>                <span class="token comment">// 写入单条 K 线</span></span>
<span class="line">  <span class="token function">BatchCreate</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> candles <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">)</span> <span class="token builtin">error</span>        <span class="token comment">// 批量写入 K 线</span></span>
<span class="line">  <span class="token function">GetBySymbolAndTimeRange</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> symbol <span class="token builtin">string</span><span class="token punctuation">,</span> start<span class="token punctuation">,</span> end time<span class="token punctuation">.</span>Time<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token comment">// 按股票代码和时间范围查询</span></span>
<span class="line">  <span class="token function">DeleteExpired</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> retentionTime time<span class="token punctuation">.</span>Duration<span class="token punctuation">)</span> <span class="token builtin">error</span>  <span class="token comment">// 删除过期数据</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// candleRepo 实现 CandleRepo 接口</span></span>
<span class="line"><span class="token keyword">type</span> candleRepo <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">  client <span class="token operator">*</span>influxdb<span class="token punctuation">.</span>Client  <span class="token comment">// 框架封装的 InfluxDB 客户端</span></span>
<span class="line">  log    <span class="token operator">*</span>log<span class="token punctuation">.</span>Helper       <span class="token comment">// 日志组件</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// NewCandleRepo 创建 K 线数据仓库实例</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewCandleRepo</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> client <span class="token operator">*</span>influxdb<span class="token punctuation">.</span>Client<span class="token punctuation">)</span> CandleRepo <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token operator">&amp;</span>candleRepo<span class="token punctuation">{</span></span>
<span class="line">    client<span class="token punctuation">:</span> client<span class="token punctuation">,</span></span>
<span class="line">    log<span class="token punctuation">:</span>    log<span class="token punctuation">.</span><span class="token function">NewHelper</span><span class="token punctuation">(</span>log<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token string">&quot;module&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;data/repo/candle&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ToPoint 将业务模型转换为 InfluxDB Point（数据写入时使用）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">ToPoint</span><span class="token punctuation">(</span>candle <span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">)</span> <span class="token operator">*</span>influxdb3<span class="token punctuation">.</span>Point <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> candle <span class="token operator">==</span> <span class="token boolean">nil</span> <span class="token operator">||</span> candle<span class="token punctuation">.</span>Timestamp <span class="token operator">==</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 初始化 Point：指定 Measurement 和时间戳</span></span>
<span class="line">  point <span class="token operator">:=</span> influxdb3<span class="token punctuation">.</span><span class="token function">NewPoint</span><span class="token punctuation">(</span></span>
<span class="line">    MeasurementCandle<span class="token punctuation">,</span></span>
<span class="line">    <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span>TagSymbol<span class="token punctuation">:</span> candle<span class="token punctuation">.</span><span class="token function">GetSymbol</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token comment">// Tag 集合</span></span>
<span class="line">    <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">{</span>                           <span class="token comment">// Field 集合</span></span>
<span class="line">      FieldOpen<span class="token punctuation">:</span>   candle<span class="token punctuation">.</span><span class="token function">GetOpen</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">      FieldHigh<span class="token punctuation">:</span>   candle<span class="token punctuation">.</span><span class="token function">GetHigh</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">      FieldLow<span class="token punctuation">:</span>    candle<span class="token punctuation">.</span><span class="token function">GetLow</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">      FieldClose<span class="token punctuation">:</span>  candle<span class="token punctuation">.</span><span class="token function">GetClose</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">      FieldVolume<span class="token punctuation">:</span> candle<span class="token punctuation">.</span><span class="token function">GetVolume</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    candle<span class="token punctuation">.</span>Timestamp<span class="token punctuation">.</span><span class="token function">AsTime</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 时间戳（转换为 time.Time 类型）</span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">return</span> point</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ToModel 将 InfluxDB Point 转换为业务模型（数据查询时使用）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">ToModel</span><span class="token punctuation">(</span>point <span class="token operator">*</span>influxdb3<span class="token punctuation">.</span>Point<span class="token punctuation">)</span> <span class="token operator">*</span>model<span class="token punctuation">.</span>Candle <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> point <span class="token operator">==</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">return</span> <span class="token operator">&amp;</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">{</span></span>
<span class="line">    Symbol<span class="token punctuation">:</span>    influxdb<span class="token punctuation">.</span><span class="token function">GetPointTagPtr</span><span class="token punctuation">(</span>point<span class="token punctuation">,</span> TagSymbol<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 从 Tag 提取股票代码（指针类型）</span></span>
<span class="line">    Open<span class="token punctuation">:</span>      point<span class="token punctuation">.</span><span class="token function">GetDoubleField</span><span class="token punctuation">(</span>FieldOpen<span class="token punctuation">)</span><span class="token punctuation">,</span>           <span class="token comment">// 从 Field 提取浮点数</span></span>
<span class="line">    High<span class="token punctuation">:</span>      point<span class="token punctuation">.</span><span class="token function">GetDoubleField</span><span class="token punctuation">(</span>FieldHigh<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    Low<span class="token punctuation">:</span>       point<span class="token punctuation">.</span><span class="token function">GetDoubleField</span><span class="token punctuation">(</span>FieldLow<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    Close<span class="token punctuation">:</span>     point<span class="token punctuation">.</span><span class="token function">GetDoubleField</span><span class="token punctuation">(</span>FieldClose<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    Volume<span class="token punctuation">:</span>    point<span class="token punctuation">.</span><span class="token function">GetDoubleField</span><span class="token punctuation">(</span>FieldVolume<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    Timestamp<span class="token punctuation">:</span> timestamppb<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span>point<span class="token punctuation">.</span>Values<span class="token punctuation">.</span>Timestamp<span class="token punctuation">)</span><span class="token punctuation">,</span>   <span class="token comment">// 时间戳转换为 protobuf 类型</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Create 写入单条 K 线数据</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">Create</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> candle <span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> candle <span class="token operator">==</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;创建 K 线失败：请求数据为空&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> errorx<span class="token punctuation">.</span><span class="token function">NewBadRequestError</span><span class="token punctuation">(</span><span class="token string">&quot;request data is required&quot;</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 框架封装的插入方法：自动转换模型为 Point 并写入</span></span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">:=</span> influxdb<span class="token punctuation">.</span><span class="token function">Insert</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> r<span class="token punctuation">.</span>client<span class="token punctuation">,</span> candle<span class="token punctuation">,</span> r<span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;写入 K 线数据失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;symbol&quot;</span><span class="token punctuation">,</span> candle<span class="token punctuation">.</span><span class="token function">GetSymbol</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;error&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> errorx<span class="token punctuation">.</span><span class="token function">NewDataBaseError</span><span class="token punctuation">(</span><span class="token string">&quot;insert candle failed&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// BatchCreate 批量写入 K 线数据（高性能推荐）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">BatchCreate</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> candles <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> <span class="token function">len</span><span class="token punctuation">(</span>candles<span class="token punctuation">)</span> <span class="token operator">==</span> <span class="token number">0</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> errorx<span class="token punctuation">.</span><span class="token function">NewBadRequestError</span><span class="token punctuation">(</span><span class="token string">&quot;batch data is empty&quot;</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 转换为 Point 列表</span></span>
<span class="line">  points <span class="token operator">:=</span> <span class="token function">make</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>influxdb3<span class="token punctuation">.</span>Point<span class="token punctuation">,</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token function">len</span><span class="token punctuation">(</span>candles<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> c <span class="token operator">:=</span> <span class="token keyword">range</span> candles <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">if</span> p <span class="token operator">:=</span> r<span class="token punctuation">.</span><span class="token function">ToPoint</span><span class="token punctuation">(</span>c<span class="token punctuation">)</span><span class="token punctuation">;</span> p <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">      points <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>points<span class="token punctuation">,</span> p<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 批量写入：减少网络交互，提升性能</span></span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">:=</span> r<span class="token punctuation">.</span>client<span class="token punctuation">.</span><span class="token function">WritePoints</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> points<span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;批量写入 K 线失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;count&quot;</span><span class="token punctuation">,</span> <span class="token function">len</span><span class="token punctuation">(</span>candles<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;error&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> errorx<span class="token punctuation">.</span><span class="token function">NewDataBaseError</span><span class="token punctuation">(</span><span class="token string">&quot;batch insert candle failed&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Infow</span><span class="token punctuation">(</span><span class="token string">&quot;批量写入 K 线成功&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;count&quot;</span><span class="token punctuation">,</span> <span class="token function">len</span><span class="token punctuation">(</span>points<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// GetBySymbolAndTimeRange 按股票代码和时间范围查询 K 线</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">GetBySymbolAndTimeRange</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> symbol <span class="token builtin">string</span><span class="token punctuation">,</span> start<span class="token punctuation">,</span> end time<span class="token punctuation">.</span>Time<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">if</span> symbol <span class="token operator">==</span> <span class="token string">&quot;&quot;</span> <span class="token operator">||</span> start<span class="token punctuation">.</span><span class="token function">After</span><span class="token punctuation">(</span>end<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> errorx<span class="token punctuation">.</span><span class="token function">NewBadRequestError</span><span class="token punctuation">(</span><span class="token string">&quot;invalid symbol or time range&quot;</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 构建 SQL 查询语句（InfluxDB 3.x 支持标准 SQL）</span></span>
<span class="line">  sql <span class="token operator">:=</span> <span class="token string">\`</span>
<span class="line">    SELECT * FROM $measurement </span>
<span class="line">    WHERE symbol = $symbol </span>
<span class="line">      AND time BETWEEN $start AND $end </span>
<span class="line">    ORDER BY time ASC</span>
<span class="line">  \`</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 执行查询：框架封装的查询方法，自动映射结果为模型列表</span></span>
<span class="line">  <span class="token keyword">var</span> candles <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>model<span class="token punctuation">.</span>Candle</span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">:=</span> influxdb<span class="token punctuation">.</span><span class="token function">Query</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> r<span class="token punctuation">.</span>client<span class="token punctuation">,</span> <span class="token operator">&amp;</span>candles<span class="token punctuation">,</span> r<span class="token punctuation">,</span> sql<span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;measurement&quot;</span><span class="token punctuation">,</span> MeasurementCandle<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;symbol&quot;</span><span class="token punctuation">,</span> symbol<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;start&quot;</span><span class="token punctuation">,</span> start<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;end&quot;</span><span class="token punctuation">,</span> end<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;查询 K 线失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;symbol&quot;</span><span class="token punctuation">,</span> symbol<span class="token punctuation">,</span> <span class="token string">&quot;start&quot;</span><span class="token punctuation">,</span> start<span class="token punctuation">,</span> <span class="token string">&quot;end&quot;</span><span class="token punctuation">,</span> end<span class="token punctuation">,</span> <span class="token string">&quot;error&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> errorx<span class="token punctuation">.</span><span class="token function">NewDataBaseError</span><span class="token punctuation">(</span><span class="token string">&quot;query candle failed&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">return</span> candles<span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// DeleteExpired 删除过期 K 线数据（也可通过 InfluxDB 保留策略自动清理）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>r <span class="token operator">*</span>candleRepo<span class="token punctuation">)</span> <span class="token function">DeleteExpired</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> retentionTime time<span class="token punctuation">.</span>Duration<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">  expiredTime <span class="token operator">:=</span> time<span class="token punctuation">.</span><span class="token function">Now</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Add</span><span class="token punctuation">(</span><span class="token operator">-</span>retentionTime<span class="token punctuation">)</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 构建删除 SQL</span></span>
<span class="line">  sql <span class="token operator">:=</span> <span class="token string">\`</span>
<span class="line">    DELETE FROM $measurement </span>
<span class="line">    WHERE time &lt; $expiredTime</span>
<span class="line">  \`</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">:=</span> r<span class="token punctuation">.</span>client<span class="token punctuation">.</span><span class="token function">Exec</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> sql<span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;measurement&quot;</span><span class="token punctuation">,</span> MeasurementCandle<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    influxdb<span class="token punctuation">.</span><span class="token function">WithQueryParam</span><span class="token punctuation">(</span><span class="token string">&quot;expiredTime&quot;</span><span class="token punctuation">,</span> expiredTime<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Errorw</span><span class="token punctuation">(</span><span class="token string">&quot;删除过期 K 线失败&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;expiredTime&quot;</span><span class="token punctuation">,</span> expiredTime<span class="token punctuation">,</span> <span class="token string">&quot;error&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span> errorx<span class="token punctuation">.</span><span class="token function">NewDataBaseError</span><span class="token punctuation">(</span><span class="token string">&quot;delete expired candle failed&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">)</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  r<span class="token punctuation">.</span>log<span class="token punctuation">.</span><span class="token function">Infow</span><span class="token punctuation">(</span><span class="token string">&quot;删除过期 K 线成功&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;expiredBefore&quot;</span><span class="token punctuation">,</span> expiredTime<span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-6-业务层调用示例" tabindex="-1"><a class="header-anchor" href="#_4-6-业务层调用示例"><span>4.6 业务层调用示例</span></a></h3><p>在 <code>internal/service/candle_service.go</code> 中调用数据仓库，实现业务逻辑：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> service</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">  <span class="token string">&quot;context&quot;</span></span>
<span class="line">  <span class="token string">&quot;time&quot;</span></span>
<span class="line"></span>
<span class="line">  <span class="token string">&quot;github.com/go-kratos/kratos/v2/log&quot;</span></span>
<span class="line"></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/data/model&quot;</span></span>
<span class="line">  <span class="token string">&quot;your-project-path/internal/data/repo&quot;</span></span>
<span class="line">  <span class="token string">&quot;your-project-path/api/candle/v1&quot;</span>  <span class="token comment">// Protobuf 接口定义</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> CandleService <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">  candlev1<span class="token punctuation">.</span>UnimplementedCandleServiceServer</span>
<span class="line">  candleRepo repo<span class="token punctuation">.</span>CandleRepo</span>
<span class="line">  log        <span class="token operator">*</span>log<span class="token punctuation">.</span>Helper</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewCandleService</span><span class="token punctuation">(</span>candleRepo repo<span class="token punctuation">.</span>CandleRepo<span class="token punctuation">,</span> logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> <span class="token operator">*</span>CandleService <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token operator">&amp;</span>CandleService<span class="token punctuation">{</span></span>
<span class="line">    candleRepo<span class="token punctuation">:</span> candleRepo<span class="token punctuation">,</span></span>
<span class="line">    log<span class="token punctuation">:</span>        log<span class="token punctuation">.</span><span class="token function">NewHelper</span><span class="token punctuation">(</span>log<span class="token punctuation">.</span><span class="token function">With</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token string">&quot;module&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;service/candle&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// CreateCandle 写入单条 K 线（RPC 接口实现）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>s <span class="token operator">*</span>CandleService<span class="token punctuation">)</span> <span class="token function">CreateCandle</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> req <span class="token operator">*</span>candlev1<span class="token punctuation">.</span>CreateCandleRequest<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>candlev1<span class="token punctuation">.</span>CreateCandleResponse<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token comment">// 转换 Protobuf 请求为业务模型</span></span>
<span class="line">  candle <span class="token operator">:=</span> <span class="token operator">&amp;</span>model<span class="token punctuation">.</span>Candle<span class="token punctuation">{</span></span>
<span class="line">    Symbol<span class="token punctuation">:</span>    <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>Symbol<span class="token punctuation">,</span></span>
<span class="line">    Open<span class="token punctuation">:</span>      <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>Open<span class="token punctuation">,</span></span>
<span class="line">    High<span class="token punctuation">:</span>      <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>High<span class="token punctuation">,</span></span>
<span class="line">    Low<span class="token punctuation">:</span>       <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>Low<span class="token punctuation">,</span></span>
<span class="line">    Close<span class="token punctuation">:</span>     <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>Close<span class="token punctuation">,</span></span>
<span class="line">    Volume<span class="token punctuation">:</span>    <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>Volume<span class="token punctuation">,</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  candle<span class="token punctuation">.</span><span class="token function">SetTimestamp</span><span class="token punctuation">(</span>time<span class="token punctuation">.</span><span class="token function">UnixMilli</span><span class="token punctuation">(</span>req<span class="token punctuation">.</span>Timestamp<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment">// 转换时间戳（毫秒级）</span></span>
<span class="line">  </span>
<span class="line">  <span class="token comment">// 调用数据仓库写入数据</span></span>
<span class="line">  <span class="token keyword">if</span> err <span class="token operator">:=</span> s<span class="token punctuation">.</span>candleRepo<span class="token punctuation">.</span><span class="token function">Create</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> candle<span class="token punctuation">)</span><span class="token punctuation">;</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> err</span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">return</span> <span class="token operator">&amp;</span>candlev1<span class="token punctuation">.</span>CreateCandleResponse<span class="token punctuation">{</span>Success<span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 其他业务方法（批量写入、查询、删除）类似，省略...</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、常见问题排查与最佳实践" tabindex="-1"><a class="header-anchor" href="#五、常见问题排查与最佳实践"><span>五、常见问题排查与最佳实践</span></a></h2><h3 id="_5-1-集成常见问题" tabindex="-1"><a class="header-anchor" href="#_5-1-集成常见问题"><span>5.1 集成常见问题</span></a></h3><h4 id="问题-1-客户端连接失败排查方向-服务端地址是否正确、端口是否开放、token-是否有效" tabindex="-1"><a class="header-anchor" href="#问题-1-客户端连接失败排查方向-服务端地址是否正确、端口是否开放、token-是否有效"><span>问题 1：客户端连接失败排查方向：服务端地址是否正确、端口是否开放、Token 是否有效；</span></a></h4><p>解决方案：执行 <code>curl http://localhost:8181/health</code> 检查服务可用性，确认配置文件中 <code>host</code> 和 <code>token</code> 参数正确。</p><h4 id="问题-2-数据写入后查询不到排查方向-时间戳是否为-utc-时间、measurement-tag-field-名称是否匹配、保留策略是否正确" tabindex="-1"><a class="header-anchor" href="#问题-2-数据写入后查询不到排查方向-时间戳是否为-utc-时间、measurement-tag-field-名称是否匹配、保留策略是否正确"><span>问题 2：数据写入后查询不到排查方向：时间戳是否为 UTC 时间、Measurement/Tag/Field 名称是否匹配、保留策略是否正确；</span></a></h4><p>解决方案：在 Explorer 中直接执行 SQL 查询验证，检查数据模型与 InfluxDB 结构的映射关系。</p><h4 id="问题-3-批量写入性能差排查方向-是否使用批量写入接口、单次写入点数是否合理" tabindex="-1"><a class="header-anchor" href="#问题-3-批量写入性能差排查方向-是否使用批量写入接口、单次写入点数是否合理"><span>问题 3：批量写入性能差排查方向：是否使用批量写入接口、单次写入点数是否合理；</span></a></h4><p>解决方案：使用 <code>BatchCreate</code> 方法，单次写入点数建议控制在 1000-5000 条，减少网络交互次数。</p><h3 id="_5-2-最佳实践建议" tabindex="-1"><a class="header-anchor" href="#_5-2-最佳实践建议"><span>5.2 最佳实践建议</span></a></h3><ol><li><strong>Tag 与 Field 设计原则</strong>：高频过滤字段设为 Tag（如设备 ID、股票代码），高频写入的数值字段设为 Field；避免将高基数字段（如 UUID）设为 Tag，否则会导致 Series 数量暴增。</li><li><strong>数据保留策略</strong>：根据业务需求自定义保留策略，例如实时监控数据保留 7 天，历史归档数据保留 1 年；通过连续查询（CQ）实现数据降采样（如将 1 分钟数据聚合为 5 分钟数据）。</li><li><strong>性能优化</strong>：批量写入时使用 <code>WritePoints</code> 接口，查询时指定时间范围和必要字段（避免 <code>SELECT *</code>），利用 InfluxDB 3.x 的列式存储优势。</li><li><strong>安全配置</strong>：生产环境启用 HTTPS 加密传输，创建专用业务用户并分配最小权限，定期轮换 Token。</li></ol><h2 id="六、项目代码与资源" tabindex="-1"><a class="header-anchor" href="#六、项目代码与资源"><span>六、项目代码与资源</span></a></h2><p>完整项目代码可通过以下仓库获取，包含 InfluxDB 集成的全部示例代码：</p><ul><li>GoWind Admin 官方仓库（Gitee）：<a href="https://gitee.com/tx7do/go-wind-admin" target="_blank" rel="noopener noreferrer">https://gitee.com/tx7do/go-wind-admin</a></li><li>GoWind Admin 官方仓库（GitHub）：<a href="https://github.com/tx7do/go-wind-admin" target="_blank" rel="noopener noreferrer">https://github.com/tx7do/go-wind-admin</a></li><li>InfluxDB 3.x 官方文档：<a href="https://docs.influxdata.com/influxdb/latest/" target="_blank" rel="noopener noreferrer">https://docs.influxdata.com/influxdb/latest/</a></li></ul>`,67)])])}const i=s(t,[["render",l]]),u=JSON.parse('{"path":"/posts/go_wind_admin_influxdb.html","title":"GoWind Admin｜风行 — 开箱即用的企业级全栈中后台框架：InfluxDB集成指南","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["GoWind风行"],"tag":["Golang","Go-Kratos","GoWind"],"sticky":10},"headers":[{"level":2,"title":"一、InfluxDB 核心概念深度解析","slug":"一、influxdb-核心概念深度解析","link":"#一、influxdb-核心概念深度解析","children":[]},{"level":2,"title":"二、InfluxDB 2.x 与 3.x 核心差异对比","slug":"二、influxdb-2-x-与-3-x-核心差异对比","link":"#二、influxdb-2-x-与-3-x-核心差异对比","children":[{"level":3,"title":"2.1 存储引擎：从 TSM 到 IOx 的代际飞跃","slug":"_2-1-存储引擎-从-tsm-到-iox-的代际飞跃","link":"#_2-1-存储引擎-从-tsm-到-iox-的代际飞跃","children":[]},{"level":3,"title":"2.2 查询语言：从 Flux 回归标准 SQL","slug":"_2-2-查询语言-从-flux-回归标准-sql","link":"#_2-2-查询语言-从-flux-回归标准-sql","children":[]},{"level":3,"title":"2.3 架构与扩展性：从单体到分布式云原生","slug":"_2-3-架构与扩展性-从单体到分布式云原生","link":"#_2-3-架构与扩展性-从单体到分布式云原生","children":[]}]},{"level":2,"title":"三、InfluxDB 3.x Docker 部署指南（推荐）","slug":"三、influxdb-3-x-docker-部署指南-推荐","link":"#三、influxdb-3-x-docker-部署指南-推荐","children":[{"level":3,"title":"3.1 部署 InfluxDB 3.x 服务端","slug":"_3-1-部署-influxdb-3-x-服务端","link":"#_3-1-部署-influxdb-3-x-服务端","children":[]},{"level":3,"title":"3.2 部署 InfluxDB Explorer 管理后台","slug":"_3-2-部署-influxdb-explorer-管理后台","link":"#_3-2-部署-influxdb-explorer-管理后台","children":[]},{"level":3,"title":"3.3 部署验证与初始化配置","slug":"_3-3-部署验证与初始化配置","link":"#_3-3-部署验证与初始化配置","children":[]},{"level":3,"title":"3.4 2.x 版本部署（兼容参考）","slug":"_3-4-2-x-版本部署-兼容参考","link":"#_3-4-2-x-版本部署-兼容参考","children":[]}]},{"level":2,"title":"四、GoWind Admin 集成 InfluxDB 3.x 完整步骤","slug":"四、gowind-admin-集成-influxdb-3-x-完整步骤","link":"#四、gowind-admin-集成-influxdb-3-x-完整步骤","children":[{"level":3,"title":"4.1 安装依赖库","slug":"_4-1-安装依赖库","link":"#_4-1-安装依赖库","children":[]},{"level":3,"title":"4.2 配置文件编写","slug":"_4-2-配置文件编写","link":"#_4-2-配置文件编写","children":[]},{"level":3,"title":"4.3 客户端初始化与依赖注入","slug":"_4-3-客户端初始化与依赖注入","link":"#_4-3-客户端初始化与依赖注入","children":[]},{"level":3,"title":"4.4 业务模型定义","slug":"_4-4-业务模型定义","link":"#_4-4-业务模型定义","children":[]},{"level":3,"title":"4.5 数据仓库实现（完整 CRUD）","slug":"_4-5-数据仓库实现-完整-crud","link":"#_4-5-数据仓库实现-完整-crud","children":[]},{"level":3,"title":"4.6 业务层调用示例","slug":"_4-6-业务层调用示例","link":"#_4-6-业务层调用示例","children":[]}]},{"level":2,"title":"五、常见问题排查与最佳实践","slug":"五、常见问题排查与最佳实践","link":"#五、常见问题排查与最佳实践","children":[{"level":3,"title":"5.1 集成常见问题","slug":"_5-1-集成常见问题","link":"#_5-1-集成常见问题","children":[]},{"level":3,"title":"5.2 最佳实践建议","slug":"_5-2-最佳实践建议","link":"#_5-2-最佳实践建议","children":[]}]},{"level":2,"title":"六、项目代码与资源","slug":"六、项目代码与资源","link":"#六、项目代码与资源","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":6,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"9ee9593d10296afa6d6a136d0fec19daa5fa3aad","time":1769485475000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add posts."},{"hash":"010e3215f55190804ae072b007c76eaf933f80c7","time":1765524468000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts"},{"hash":"ae111c1195e0474d663bce54e67cfce0cfdaa8fe","time":1765461806000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit posts."},{"hash":"804838588c89d5377e42d5674396d1e01376f070","time":1762916948000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit post."},{"hash":"af861e56e1afafbaf328d0f8b2ea8fde09c7063f","time":1752575760000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: add posts."}]},"filePathRelative":"posts/go_wind_admin_influxdb.md","excerpt":"\\n<p>InfluxDB 是一款采用 Go 语言开发的开源分布式时序数据库，专为时间序列数据的高效存储、查询与分析设计，由 InfluxData 公司主导开发。其核心优势在于高频写入性能、时序数据索引优化及原生聚合分析能力，广泛应用于 IoT 设备监控、系统性能指标采集、日志时序分析、金融行情跟踪等场景。在企业级中后台系统中，InfluxDB 可快速对接 GoWind Admin 框架，为实时监控面板、历史数据追溯、趋势预测分析等功能提供稳定的数据存储支撑。</p>\\n<h2>一、InfluxDB 核心概念深度解析</h2>\\n<p>InfluxDB 的数据模型与传统关系型数据库存在显著差异，理解以下核心概念是实现高效集成的基础。可通过与 MySQL 概念的类比快速建立认知：</p>"}');export{i as comp,u as data};
